import { useState, useMemo } from "react";
import { api as http } from "../uiApiCompat";
import { usePoll } from "../hooks/usePoll";
import { useAppStore } from "../store/appStore";
import V2EmptyState from "../components/V2EmptyState";

/* ── helpers ─────────────────────────────────────────── */
const driftColor = (v) => {
  if (v < 0.1) return "v2-green";
  if (v < 0.2) return "v2-amber";
  return "v2-red";
};
const urgencyColor = (u) => {
  if (u === "HIGH") return "v2-red";
  if (u === "MEDIUM") return "v2-amber";
  return "v2-green";
};
const fmtPct = (v) => v == null ? "--" : `${(v * 100).toFixed(1)}%`;
const fmtDelta = (v) => {
  if (v == null) return "--";
  return `${v >= 0 ? "+" : ""}${(v * 100).toFixed(1)}%`;
};
const toneDelta = (v) => v == null ? "blue" : v >= 0 ? "green" : "red";

/* ── stat card ───────────────────────────────────────── */
function Stat({ label, value, tone = "blue", sub = "" }) {
  return (
    <div className="v2-card">
      <div className="v2-ct">{label}</div>
      <div className={`v2-cv v2-${tone}`}>{value}</div>
      {sub && <div className="v2-muted" style={{ marginTop: 8 }}>{sub}</div>}
    </div>
  );
}

/* ── main page ───────────────────────────────────────── */
export default function Drift() {
  const { state, toast } = useAppStore();
  const [psiThreshold, setPsiThreshold] = useState(0.20);
  const [ksThreshold, setKsThreshold] = useState(0.15);
  const [autoRetrain, setAutoRetrain] = useState(false);
  const [featureSortCol, setFeatureSortCol] = useState("psi");
  const [featureSortAsc, setFeatureSortAsc] = useState(false);

  /* poll model drift data */
  const { data: driftData, loading } = usePoll(
    async () => { const r = await http.get("/v2/model-drift"); return r.data; },
    { intervalMs: 15000, enabled: !state.offlineMode }
  );

  const rawStrategies = driftData?.strategies ?? [];
  /* normalise: API returns "id" for the strategy key, pages expect "strategy" or "name" */
  const strategies = rawStrategies.map(s => ({
    ...s,
    strategy: s.strategy ?? s.name ?? s.id,
    name: s.name ?? s.strategy ?? s.id,
  }));
  const driftMetrics = driftData?.metrics ?? null;
  const featureDrift = driftData?.feature_drift ?? [];
  const timeline = driftData?.timeline ?? [];
  const recommendations = driftData?.recommendations ?? [];

  /* derived top-level stats */
  const avgDrift = strategies.length > 0
    ? strategies.reduce((a, s) => a + (s.drift_score ?? 0), 0) / strategies.length
    : null;
  const avgPsi = driftMetrics?.avg_psi ?? driftMetrics?.psi ?? driftMetrics?.max_drift_score ?? null;
  const avgKs = driftMetrics?.avg_ks ?? driftMetrics?.ks ?? driftMetrics?.win_rate_drift ?? null;
  const daysSinceRetrain = driftMetrics?.days_since_retrain ?? null;
  /* API metrics also exposes: sharpe_drift, total_strategies, strategies_with_live_data */
  const driftingCount = strategies.filter(s => (s.status ?? "").toUpperCase().includes("DRIFT")).length;

  /* sort feature drift */
  const sortedFeatures = useMemo(() => {
    const list = [...featureDrift];
    list.sort((a, b) => {
      const va = a[featureSortCol] ?? 0;
      const vb = b[featureSortCol] ?? 0;
      return featureSortAsc ? (va > vb ? 1 : -1) : (va < vb ? 1 : -1);
    });
    return list;
  }, [featureDrift, featureSortCol, featureSortAsc]);

  const handleFeatureSort = (col) => {
    if (featureSortCol === col) setFeatureSortAsc(!featureSortAsc);
    else { setFeatureSortCol(col); setFeatureSortAsc(false); }
  };
  const sortInd = (col) => featureSortCol === col ? (featureSortAsc ? " \u25B2" : " \u25BC") : "";

  if (loading) {
    return (
      <>
        <div className="v2-pagehead">
          <div>
            <h1 className="v2-h1">Model Drift Detection</h1>
            <div className="v2-muted">Loading drift data...</div>
          </div>
        </div>
        <div className="v2-grid">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="v2-card">
              <div className="v2-ct">Loading...</div>
              <div className="v2-cv v2-blue" style={{ opacity: 0.3 }}>--</div>
            </div>
          ))}
        </div>
      </>
    );
  }

  return (
    <div role="main" aria-label="Model Drift Detection">
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">Model Drift Detection</h1>
          <div className="v2-muted">Compare live performance vs expected distribution. Alert on drift.</div>
        </div>
        <div className="v2-row">
          <button className="v2-btn" onClick={() => toast("Force retrain initiated for all drifting models", "info")}>Force Retrain</button>
          <button className="v2-btn" onClick={() => toast("Baseline reset to current distribution", "info")}>Reset Baseline</button>
          <button className="v2-btn" onClick={() => toast("Drift alerts acknowledged", "info")}>Acknowledge Drift</button>
        </div>
      </div>

      {/* ── Top Stats ──────────────────────────────────── */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <Stat label="Drift Score" value={avgDrift != null ? avgDrift.toFixed(3) : "--"} tone={avgDrift != null ? driftColor(avgDrift).replace("v2-", "") : "blue"} sub={driftingCount > 0 ? `${driftingCount} models drifting` : "No drift data"} />
        <Stat label="PSI Index" value={avgPsi != null ? avgPsi.toFixed(3) : "--"} tone={avgPsi != null ? (avgPsi < 0.1 ? "green" : avgPsi < 0.2 ? "amber" : "red") : "blue"} sub="Population Stability" />
        <Stat label="KS Statistic" value={avgKs != null ? avgKs.toFixed(3) : "--"} tone={avgKs != null ? (avgKs < 0.1 ? "green" : avgKs < 0.2 ? "amber" : "red") : "blue"} sub="Kolmogorov-Smirnov" />
        <Stat label="Days Since Retrain" value={daysSinceRetrain != null ? daysSinceRetrain : "--"} tone={daysSinceRetrain != null ? (daysSinceRetrain < 7 ? "green" : daysSinceRetrain < 14 ? "amber" : "red") : "blue"} sub={daysSinceRetrain != null ? "Last model update" : "No retrain data"} />
      </div>

      <div className="v2-grid">
        {/* ── Drift Score Timeline (SVG) ─────────────── */}
        <div className="v2-card wide">
          <div className="v2-ct">Drift Score Timeline - Last 30 Days</div>
          {timeline.length === 0 && strategies.length === 0 ? (
            <V2EmptyState icon={"\u29C6"} title="No Drift Timeline" message="Daily drift score history will appear when the drift detection pipeline produces output." />
          ) : (() => {
            const points = timeline.length > 0 ? timeline : strategies.map((s, i) => ({ day: i, score: s.drift_score ?? 0 }));
            if (points.length === 0) return <V2EmptyState icon={"\u29C6"} title="No Timeline Data" message="No drift timeline data available." />;
            const maxScore = Math.max(0.3, ...points.map(p => p.score ?? p.drift_score ?? 0));
            const w = 700, h = 100, padX = 30, padY = 10;
            const plotW = w - padX * 2, plotH = h - padY * 2;
            const pts = points.map((p, i) => {
              const x = padX + (i / Math.max(points.length - 1, 1)) * plotW;
              const val = p.score ?? p.drift_score ?? 0;
              const y = padY + plotH - (val / maxScore) * plotH;
              return { x, y, val };
            });
            const linePath = pts.map((p, i) => `${i === 0 ? "M" : "L"} ${p.x.toFixed(1)} ${p.y.toFixed(1)}`).join(" ");
            /* threshold lines */
            const psiY = padY + plotH - (psiThreshold / maxScore) * plotH;
            const ksY = padY + plotH - (ksThreshold / maxScore) * plotH;
            return (
              <svg viewBox={`0 0 ${w} ${h}`} style={{ width: "100%", display: "block", marginTop: 8 }}>
                {/* grid lines */}
                {[0, 0.25, 0.5, 0.75, 1].map(frac => {
                  const y = padY + plotH * (1 - frac);
                  return <line key={frac} x1={padX} y1={y} x2={w - padX} y2={y} stroke="rgba(255,255,255,0.05)" strokeWidth="0.5" />;
                })}
                {/* threshold lines */}
                <line x1={padX} y1={psiY} x2={w - padX} y2={psiY} stroke="rgba(255,210,120,0.4)" strokeWidth="1" strokeDasharray="4,3" />
                <text x={w - padX + 4} y={psiY + 3} fill="rgba(255,210,120,0.6)" fontSize="7">PSI</text>
                <line x1={padX} y1={ksY} x2={w - padX} y2={ksY} stroke="rgba(255,140,140,0.4)" strokeWidth="1" strokeDasharray="4,3" />
                <text x={w - padX + 4} y={ksY + 3} fill="rgba(255,140,140,0.6)" fontSize="7">KS</text>
                {/* line */}
                <path d={linePath} fill="none" stroke="rgba(150,190,255,0.8)" strokeWidth="1.5" />
                {/* area */}
                <path d={`${linePath} L ${pts[pts.length - 1].x.toFixed(1)} ${padY + plotH} L ${pts[0].x.toFixed(1)} ${padY + plotH} Z`}
                  fill="rgba(150,190,255,0.08)" />
                {/* dots */}
                {pts.map((p, i) => (
                  <circle key={i} cx={p.x} cy={p.y} r="2.5"
                    fill={p.val > psiThreshold ? "var(--v2-red)" : p.val > ksThreshold ? "var(--v2-amber)" : "var(--v2-green)"} />
                ))}
                {/* axis labels */}
                <text x={padX} y={h - 1} fill="rgba(255,255,255,0.3)" fontSize="7">Day 1</text>
                <text x={w - padX} y={h - 1} fill="rgba(255,255,255,0.3)" fontSize="7" textAnchor="end">Day {points.length}</text>
                <text x={padX - 4} y={padY + 4} fill="rgba(255,255,255,0.3)" fontSize="7" textAnchor="end">{maxScore.toFixed(2)}</text>
                <text x={padX - 4} y={padY + plotH + 4} fill="rgba(255,255,255,0.3)" fontSize="7" textAnchor="end">0</text>
              </svg>
            );
          })()}
        </div>

        {/* ── Distribution Comparison (paired bars) ──── */}
        <div className="v2-card half">
          <div className="v2-ct">Distribution Comparison - Returns</div>
          {strategies.length === 0 ? (
            <V2EmptyState icon={"\u29C6"} title="No Distribution Data" message="Expected vs. actual return distributions will appear when drift analysis is available." />
          ) : (
            <div style={{ marginTop: 12 }}>
              {strategies.slice(0, 8).map(s => {
                const name = s.strategy ?? s.name;
                const expected = s.expected_return ?? 0;
                const actual = s.actual_return ?? (expected + (s.performance_delta ?? 0));
                const maxVal = Math.max(Math.abs(expected), Math.abs(actual), 0.01);
                return (
                  <div key={name} style={{ marginBottom: 12 }}>
                    <div style={{ fontSize: 11, marginBottom: 4 }}>{name}</div>
                    <div style={{ display: "flex", gap: 4 }}>
                      {/* expected */}
                      <div style={{ flex: 1 }}>
                        <div style={{ height: 8, borderRadius: 6, background: "rgba(255,255,255,0.06)" }}>
                          <div style={{
                            height: "100%", width: `${(Math.abs(expected) / maxVal) * 100}%`, borderRadius: 6,
                            background: "rgba(150,190,255,0.5)",
                          }} />
                        </div>
                      </div>
                      {/* actual */}
                      <div style={{ flex: 1 }}>
                        <div style={{ height: 8, borderRadius: 6, background: "rgba(255,255,255,0.06)" }}>
                          <div style={{
                            height: "100%", width: `${(Math.abs(actual) / maxVal) * 100}%`, borderRadius: 6,
                            background: actual >= expected ? "rgba(110,240,180,0.5)" : "rgba(255,120,120,0.5)",
                          }} />
                        </div>
                      </div>
                    </div>
                    <div style={{ display: "flex", justifyContent: "space-between", marginTop: 4 }}>
                      <span className="v2-mono v2-muted" style={{ fontSize: 10 }}>Exp: {fmtPct(expected)}</span>
                      <span className={`v2-mono v2-${actual >= expected ? "green" : "red"}`} style={{ fontSize: 10 }}>Act: {fmtPct(actual)}</span>
                    </div>
                  </div>
                );
              })}
              <div className="v2-row" style={{ gap: 12, marginTop: 8 }}>
                <span style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 10 }}>
                  <span style={{ width: 10, height: 6, borderRadius: 6, background: "rgba(150,190,255,0.5)", display: "inline-block" }} />
                  <span className="v2-muted">Expected</span>
                </span>
                <span style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 10 }}>
                  <span style={{ width: 10, height: 6, borderRadius: 6, background: "rgba(110,240,180,0.5)", display: "inline-block" }} />
                  <span className="v2-muted">Actual</span>
                </span>
              </div>
            </div>
          )}
        </div>

        {/* ── Alert Configuration (preserved) ────────── */}
        <div className="v2-card half">
          <div className="v2-ct">Alert Configuration</div>
          <div style={{ display: "flex", flexDirection: "column", gap: 16, marginTop: 8 }}>
            <div>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                <span style={{ fontSize: 13 }}>PSI Threshold</span>
                <span className="v2-mono v2-amber" style={{ fontSize: 13 }}>{psiThreshold.toFixed(2)}</span>
              </div>
              <input
                className="v2-input"
                type="range" min="0.05" max="0.50" step="0.01"
                value={psiThreshold}
                onChange={(e) => setPsiThreshold(parseFloat(e.target.value))}
                style={{ width: "100%" }}
              />
              <div className="v2-muted" style={{ fontSize: 10, marginTop: 4 }}>Features with PSI above this trigger alerts</div>
            </div>
            <div>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                <span style={{ fontSize: 13 }}>KS Threshold</span>
                <span className="v2-mono v2-amber" style={{ fontSize: 13 }}>{ksThreshold.toFixed(2)}</span>
              </div>
              <input
                className="v2-input"
                type="range" min="0.05" max="0.50" step="0.01"
                value={ksThreshold}
                onChange={(e) => setKsThreshold(parseFloat(e.target.value))}
                style={{ width: "100%" }}
              />
              <div className="v2-muted" style={{ fontSize: 10, marginTop: 4 }}>Distribution divergence threshold</div>
            </div>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "8px 0", borderTop: "1px solid var(--v2-border)" }}>
              <div>
                <span style={{ fontSize: 13 }}>Auto-Retrain</span>
                <div className="v2-muted" style={{ fontSize: 10 }}>Automatically retrain when drift exceeds thresholds</div>
              </div>
              <button
                className="v2-btn"
                style={{
                  background: autoRetrain ? "rgba(110,240,180,0.15)" : "rgba(255,255,255,0.06)",
                  borderColor: autoRetrain ? "rgba(110,240,180,0.3)" : "var(--v2-border)",
                  minWidth: 60,
                }}
                onClick={() => { setAutoRetrain(!autoRetrain); toast(autoRetrain ? "Auto-retrain disabled" : "Auto-retrain enabled", "info"); }}
              >
                {autoRetrain ? "ON" : "OFF"}
              </button>
            </div>
            <div style={{ padding: "8px 0", borderTop: "1px solid var(--v2-border)" }}>
              <div style={{ display: "flex", justifyContent: "space-between" }}>
                <span className="v2-muted" style={{ fontSize: 11 }}>Max retrain interval</span>
                <span className="v2-mono" style={{ fontSize: 11 }}>14 days</span>
              </div>
              <div style={{ display: "flex", justifyContent: "space-between", marginTop: 4 }}>
                <span className="v2-muted" style={{ fontSize: 11 }}>Alert recipients</span>
                <span className="v2-mono" style={{ fontSize: 11 }}>operator@aura.io</span>
              </div>
              <div style={{ display: "flex", justifyContent: "space-between", marginTop: 4 }}>
                <span className="v2-muted" style={{ fontSize: 11 }}>Alert channel</span>
                <span className="v2-mono" style={{ fontSize: 11 }}>Slack + Email</span>
              </div>
            </div>
          </div>
        </div>

        {/* ── Feature Drift Table (sortable) ─────────── */}
        <div className="v2-card wide">
          <div className="v2-ct">Feature Drift Analysis</div>
          {sortedFeatures.length === 0 ? (
            <V2EmptyState icon={"\u29C6"} title="No Feature Drift Data" message="Per-feature drift metrics (PSI, KS, mean shift) will appear when drift analysis runs." />
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "160px 90px 90px 100px 80px 1fr" }}>
                <span>Feature</span>
                <span style={{ cursor: "pointer" }} onClick={() => handleFeatureSort("psi")}>PSI{sortInd("psi")}</span>
                <span style={{ cursor: "pointer" }} onClick={() => handleFeatureSort("ks")}>KS{sortInd("ks")}</span>
                <span style={{ cursor: "pointer" }} onClick={() => handleFeatureSort("mean_shift")}>Mean Shift{sortInd("mean_shift")}</span>
                <span>Status</span>
                <span>Drift Bar</span>
              </div>
              {sortedFeatures.map((f, i) => {
                const psi = f.psi ?? 0;
                const ks = f.ks ?? 0;
                const maxDriftVal = Math.max(...sortedFeatures.map(x => x.psi ?? 0), 0.3);
                const barPct = (psi / maxDriftVal) * 100;
                const status = psi > psiThreshold || ks > ksThreshold ? "DRIFT" : "STABLE";
                return (
                  <div key={f.feature ?? f.name ?? i} className="v2-tr" style={{ gridTemplateColumns: "160px 90px 90px 100px 80px 1fr" }}>
                    <span style={{ fontWeight: 600 }}>{f.feature ?? f.name}</span>
                    <span className={`v2-mono v2-${psi > psiThreshold ? "red" : psi > psiThreshold * 0.7 ? "amber" : "green"}`}>{psi.toFixed(3)}</span>
                    <span className={`v2-mono v2-${ks > ksThreshold ? "red" : ks > ksThreshold * 0.7 ? "amber" : "green"}`}>{ks.toFixed(3)}</span>
                    <span className="v2-mono v2-muted">{f.mean_shift != null ? `${f.mean_shift >= 0 ? "+" : ""}${f.mean_shift.toFixed(3)}` : "--"}</span>
                    <span className={`v2-${status === "DRIFT" ? "red" : "green"}`} style={{ fontWeight: 600, fontSize: 11 }}>{status}</span>
                    <span>
                      <div style={{ height: 6, borderRadius: 6, background: "rgba(255,255,255,0.06)", marginTop: 4 }}>
                        <div style={{
                          height: "100%", width: `${Math.min(barPct, 100)}%`, borderRadius: 6,
                          background: status === "DRIFT"
                            ? "linear-gradient(90deg, rgba(255,120,120,0.3), rgba(255,120,120,0.8))"
                            : "linear-gradient(90deg, rgba(110,240,180,0.3), rgba(110,240,180,0.6))",
                          transition: "width 0.4s ease",
                        }} />
                      </div>
                    </span>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* ── Retrain Recommendations ────────────────── */}
        <div className="v2-card half">
          <div className="v2-ct">Retrain Recommendations</div>
          {recommendations.length === 0 && strategies.filter(s => (s.status ?? "").toUpperCase().includes("DRIFT")).length === 0 ? (
            <V2EmptyState icon={"\u29C6"} title="No Recommendations" message="Model retrain recommendations will appear when drift exceeds configured thresholds." />
          ) : (
            <div style={{ marginTop: 8, display: "flex", flexDirection: "column", gap: 8 }}>
              {(recommendations.length > 0 ? recommendations : strategies.filter(s => (s.drift_score ?? 0) > psiThreshold)).map((r, i) => {
                const name = r.strategy ?? r.model ?? r.name;
                const urgency = r.urgency ?? ((r.drift_score ?? 0) > 0.3 ? "HIGH" : (r.drift_score ?? 0) > 0.15 ? "MEDIUM" : "LOW");
                return (
                  <div key={name ?? i} style={{
                    padding: "10px 12px", borderRadius: 10,
                    background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.06)",
                  }}>
                    <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                      <span style={{ fontWeight: 600, fontSize: 13 }}>{name}</span>
                      <span className={urgencyColor(urgency)} style={{ fontWeight: 700, fontSize: 11 }}>{urgency}</span>
                    </div>
                    <div className="v2-muted" style={{ fontSize: 11 }}>
                      {r.reason ?? `Drift score ${(r.drift_score ?? 0).toFixed(3)} exceeds threshold`}
                    </div>
                    <div style={{ display: "flex", gap: 12, marginTop: 8 }}>
                      <span className="v2-mono" style={{ fontSize: 10 }}>
                        Perf delta: <span className={`v2-${toneDelta(r.performance_delta)}`}>{fmtDelta(r.performance_delta)}</span>
                      </span>
                      <span className="v2-mono" style={{ fontSize: 10 }}>
                        WR delta: <span className={`v2-${toneDelta(r.win_rate_delta)}`}>{fmtDelta(r.win_rate_delta)}</span>
                      </span>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* ── Drift Summary Panel ────────────────────── */}
        <div className="v2-card half">
          <div className="v2-ct">Drift Summary</div>
          {strategies.length === 0 ? (
            <V2EmptyState icon={"\u29C6"} title="No Summary Data" message="Drift summary metrics will appear when drift detection produces results." />
          ) : (
            <div style={{ marginTop: 8 }}>
              {/* strategy drift overview */}
              {strategies.map(s => {
                const name = s.strategy ?? s.name;
                const score = s.drift_score ?? 0;
                return (
                  <div key={name} style={{
                    display: "flex", justifyContent: "space-between", alignItems: "center",
                    padding: "6px 0", borderBottom: "1px solid rgba(255,255,255,0.04)",
                  }}>
                    <span style={{ fontSize: 13 }}>{name}</span>
                    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                      <span className={`v2-mono v2-${driftColor(score).replace("v2-", "")}`} style={{ fontSize: 13 }}>
                        {score.toFixed(3)}
                      </span>
                      <span className={`v2-${(s.status ?? "STABLE").toUpperCase().includes("DRIFT") ? "red" : "green"}`} style={{ fontSize: 10, fontWeight: 600 }}>
                        {(s.status ?? "STABLE").toUpperCase()}
                      </span>
                    </div>
                  </div>
                );
              })}
              {/* aggregate stats */}
              <div style={{ marginTop: 12, padding: "10px 0", borderTop: "1px solid rgba(255,255,255,0.08)" }}>
                {[
                  { label: "Total models tracked", value: strategies.length },
                  { label: "Models drifting", value: driftingCount, tone: driftingCount > 0 ? "red" : "green" },
                  { label: "Avg performance delta", value: fmtDelta(strategies.length > 0 ? strategies.reduce((a, s) => a + (s.performance_delta ?? 0), 0) / strategies.length : 0) },
                  { label: "Avg win rate delta", value: fmtDelta(strategies.length > 0 ? strategies.reduce((a, s) => a + (s.win_rate_delta ?? 0), 0) / strategies.length : 0) },
                ].map(m => (
                  <div key={m.label} style={{ display: "flex", justifyContent: "space-between", padding: "3px 0", fontSize: 13 }}>
                    <span className="v2-muted">{m.label}</span>
                    <span className={`v2-mono${m.tone ? ` v2-${m.tone}` : ""}`}>{m.value}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
